#!/bin/bash

ARCHIVE_DIR="/archive"
LOGFILE=$1
LOG_PATH=$(dirname $LOGFILE)
LOG_NAME=$(basename $LOGFILE)

if [ ! -d "$ARCHIVE_DIR/$LOG_PATH" ]; then
    mkdir -p "$ARCHIVE_DIR/$LOG_PATH"
fi

cp /var/log/$LOGFILE "$ARCHIVE_DIR/$LOG_PATH/$LOG_NAME"